import Foundation

// MARK: - Protocol Types

public enum AvoEnv {
    case prod
    case staging
    case dev
}

// FEATURE REQUEST: "Typed Codegen Data Structures" [BLOCKER]
// AvoEventOut is the typed output structure that replaces the old callback approach.
// Instead of: customDest.logEvent(eventName: "...", eventProperties: [...])
// You now get: let out = event.properties["analyticsDest"] → AvoEventOut(name: "...", properties: [...])
// The caller decides what to do with the typed data.
public struct AvoEventOut: @unchecked Sendable {
    // @unchecked Sendable because [String: Any] is not Sendable under strict concurrency,
    // matching the pattern used for SegmentDestination et al. in the original codegen.
    public let name: String
    public let properties: [String: Any]

    public init(name: String, properties: [String: Any]) {
        self.name = name
        self.properties = properties
    }
}

/// Errors thrown by AvoEvent.verify() implementations.
/// Contains all accumulated violation messages — verify() does NOT short-circuit on the first failure.
public struct AvoVerificationError: Error {
    public let messages: [String]

    public init(messages: [String]) {
        self.messages = messages
    }
}

// FEATURE REQUEST: "Avo Library for Common Types" [BLOCKER]
// FEATURE REQUEST: "Event Verify Method in Codegen" [Must Have]
// This protocol is the core "currency type" that the shared library exposes.
// App-specific event structs conform to this protocol.
// The library can work with any AvoEvent without knowing the concrete type.
/// This is a public protocol that should be conformed by Avo generated event structs in the app layer.
public protocol AvoEvent: Sendable {
    /// Returns per-destination enriched properties.
    /// Keys are destination identifiers (e.g., "analyticsDest", "segment").
    /// Values are AvoEventOut containing the destination-specific event name and properties
    /// (with name mapping, pinned properties, and system properties applied).
    ///
    /// Note: System properties are included by the app-level event struct directly,
    /// since different apps can have different system properties.
    ///
    /// FEATURE REQUEST: "Automated JSON Key Formatting" [Must Have]
    /// The properties dictionary contains keys already formatted per the workspace configuration.
    /// Name mapping (global, per-destination, local) is applied at generation time in each
    /// event struct's implementation of this property.
    var properties: [String: AvoEventOut] { get }

    /// The Avo event ID — a unique identifier for this event type, generated by Avo.
    /// Used for implementation status reporting (AvoInvoke) and inspector integration.
    var eventId: String { get }

    /// The Avo event hash — a content hash of the event schema, generated by Avo.
    /// Used for implementation status reporting (AvoInvoke).
    var eventHash: String { get }

    /// Validates the event's properties against schema constraints.
    /// Throws AvoVerificationError if any validation fails.
    /// Pure function — no side effects, no env guards, no reporting.
    ///
    /// FEATURE REQUEST: "Event Verify Method in Codegen" [Must Have]
    /// This method enables:
    /// - Library-level validation before sending
    /// - Integration with custom error reporting infrastructure
    /// - Unit testing of event schemas
    func verify() throws
}

// NOTE: AvoTypes (enums, object structs) are APP-SPECIFIC — each app has its own
// event schemas with their own allowed values, property types, and system properties.
// They live in AppEvents.swift alongside the event structs, not in this shared library.
// The library only provides the protocol contract (AvoEvent, AvoEventOut) and infrastructure.

// MARK: - Infrastructure

// FEATURE REQUEST: "Event Verify Method in Codegen" [Must Have]
// AvoAssert provides the validation primitives used by verify() implementations.
// Both AvoAssert and AvoAssertMessage are `internal` (not `private`) so that
// app-layer event structs can call AvoAssert.assertMin/assertMax and accumulate
// AvoAssertMessage values in their verify() implementations.
enum AvoAssertMessage {
    case expectedMax(propertyId: String, message: String)
    case expectedMin(propertyId: String, message: String)

    func getMessage() -> String {
        switch self {
        case .expectedMax(_, let message):
            return message
        case .expectedMin(_, let message):
            return message
        }
    }
}

struct AvoAssert {
    private init() {}

    static func assertMax(_ propertyId: String, _ propertyName: String, max: Double, value: Double) -> [AvoAssertMessage] {
        if (value > max) {
            return [AvoAssertMessage.expectedMax(propertyId: propertyId, message: "\(propertyName) has a maximum value of \(String(max)) but you provided the value \(String(value))")]
        } else {
            return []
        }
    }

    static func assertMax(_ propertyId: String, _ propertyName: String, max: Int, value: Int) -> [AvoAssertMessage] {
        if (value > max) {
            return [AvoAssertMessage.expectedMax(propertyId: propertyId, message: "\(propertyName) has a maximum value of \(String(max)) but you provided the value \(String(value))")]
        } else {
            return []
        }
    }

    static func assertMin(_ propertyId: String, _ propertyName: String, min: Double, value: Double) -> [AvoAssertMessage] {
        if (value < min) {
            return [AvoAssertMessage.expectedMin(propertyId: propertyId, message: "\(propertyName) has a minimum value of \(String(min)) but you provided the value \(String(value))")]
        } else {
            return []
        }
    }

    static func assertMin(_ propertyId: String, _ propertyName: String, min: Int, value: Int) -> [AvoAssertMessage] {
        if (value < min) {
            return [AvoAssertMessage.expectedMin(propertyId: propertyId, message: "\(propertyName) has a minimum value of \(String(min)) but you provided the value \(String(value))")]
        } else {
            return []
        }
    }
}

