// MARK: - Avo Actor

// FEATURE REQUEST: "Avo Library for Common Types" [BLOCKER]
// The Avo actor is OPTIONAL. It provides shared infrastructure:
// - Environment (dev/staging/prod)
// - Strict mode flag (stored but not enforced in this demo)
// - Noop mode (skips sending)
// - Inspector integration
// - Implementation status reporting (AvoInvoke)
//
// The library receives events from the app, reads their properties, verifies
// them if needed, and returns enriched event data to the caller for forwarding.
//
// System properties are APP-SPECIFIC (different apps can have different system
// properties), so they live in the app layer — each event struct includes them
// in its `properties` getter. The Avo actor does NOT store or merge system properties.
//
// WITHOUT THE AVO INSTANCE:
// - No environment gating (all code paths run)
// - No inspector integration
// - No AvoInvoke implementation-status reporting
// - No noop mode
// - No strict mode flag
// The AvoEvent protocol and AvoEventOut still work standalone — the app just
// calls event.verify() and event.properties directly.
public actor Avo {
    var __STRICT__: Bool = true
    // __STRICT__ is a named concept only in this demo.
    // Its presence here demonstrates that the variable exists for future use and
    // is absent in the no-instance path.

    public private(set) var __ENV__: AvoEnv = .prod
    public private(set) var __NOOP__: Bool = false
    var __INSPECTOR__: AnyObject?

    private init() {}

    private func configure(
        env: AvoEnv,
        inspector: AnyObject? = nil,
        strict: Bool = true,
        noop: Bool = false
    ) {
        __ENV__ = env
        __NOOP__ = noop
        __STRICT__ = strict

        // Note: In production codegen, logging will be configurable via a custom logger
        // (e.g., AvoLogger protocol with logDebug/logWarn/logError). For this demo, NSLog is used directly.
        if noop && env == .prod {
            NSLog("[avo] WARNING: Avo cannot be initialized in noop mode in production. Overwriting with noop=false.")
            __NOOP__ = false
        }
        if __NOOP__ {
            NSLog("[avo] Avo is now initialized in noop mode. No events will be sent.")
        }

        // Inspector setup
        if !__NOOP__ {
            self.__INSPECTOR__ = inspector
            if inspector != nil {
                let initSelector = Selector(("initWithApiKey:envInt:"))
                if (self.__INSPECTOR__?.responds(to: initSelector)) == true {
                    if __ENV__ == .prod {
                        let _ = self.__INSPECTOR__?.perform(initSelector, with:"YOUR_INSPECTOR_API_KEY", with:0) // Replace with your real key from the AvoInspector dashboard
                    } else if __ENV__ == .staging {
                        let _ = self.__INSPECTOR__?.perform(initSelector, with:"YOUR_INSPECTOR_API_KEY", with:2) // Replace with your real key from the AvoInspector dashboard
                    } else {
                        let _ = self.__INSPECTOR__?.perform(initSelector, with:"YOUR_INSPECTOR_API_KEY", with:1) // Replace with your real key from the AvoInspector dashboard
                    }
                }
            }
        }

        // Implementation status reporting (no-op stub in demo)
        if __ENV__ != .prod {
            AvoInvoke.invokeMeta("init", [])
        }
    }

    /// Factory method to create and configure an Avo instance.
    ///
    /// - Parameters:
    ///   - env: The environment (dev/staging/prod)
    ///   - inspector: Optional AvoInspector instance (pass nil to disable)
    ///   - strict: Stored but not enforced in this demo
    ///   - noop: When true, send() is a no-op
    public static func initAvo(
        env: AvoEnv,
        inspector: AnyObject? = nil,
        strict: Bool = true,
        noop: Bool = false
    ) async -> Avo {
        let avo = Avo()
        await avo.configure(
            env: env,
            inspector: inspector,
            strict: strict,
            noop: noop
        )
        return avo
    }

    /// Processes an event: verifies, reports to inspector, and returns per-destination enriched data.
    ///
    /// 1. Calls `event.verify()` — throws `AvoVerificationError` if validation fails
    /// 2. Reads the event's per-destination properties
    ///    (system properties are already included by the app-level event struct)
    /// 3. Reports to inspector (automatic path) if configured
    /// 4. Returns the per-destination dictionary so the caller can forward each entry to the appropriate backend
    ///
    /// - Throws: `AvoVerificationError` if the event fails schema validation.
    /// - Returns: `[String: AvoEventOut]` — per-destination enriched data. Empty if noop mode is active.
    public func process(event: AvoEvent) throws -> [String: AvoEventOut] {
        // Guard on noop
        if __NOOP__ {
            return [:]
        }

        // Verify the event — throws AvoVerificationError if validation fails
        try event.verify()

        // Report implementation status to Avo servers (no-op stub in this demo).
        // In production codegen, this POSTs to api.avo.app/i with the event's ID, hash,
        // and validation results — enabling implementation status tracking in the Avo workspace.
        if __ENV__ != .prod {
            AvoInvoke.invoke(event.eventId, event.eventHash, [])
        }

        let eventProperties = event.properties

        // Guard on empty properties
        if eventProperties.isEmpty {
            NSLog("[avo] Warning: Event has no destination properties, skipping")
            return [:]
        }

        // INSPECTOR — Automatic path: inspector is called from inside the process flow.
        // This is one of two inspector integration patterns shown in this demo.
        // See AppUsage.swift for the manual path (sendToInspector called explicitly).
        if self.__INSPECTOR__ != nil {
            let trackSchemaFromEventSelector = Selector(("avoFunctionTrackSchemaFromEvent:eventParams:"))
            if self.__INSPECTOR__?.responds(to: trackSchemaFromEventSelector) == true {
                if let firstEvent = eventProperties.values.first {
                    var inspectorProperties = firstEvent.properties
                    inspectorProperties["avoFunctionEventId"] = event.eventId
                    inspectorProperties["avoFunctionEventHash"] = event.eventHash
                    let _ = self.__INSPECTOR__?.perform(trackSchemaFromEventSelector, with: firstEvent.name, with: inspectorProperties)
                }
            }
        }

        // Return all per-destination event data — the caller forwards each to the appropriate backend
        return eventProperties
    }

    /// Reports an event to inspector manually — the second inspector integration pattern.
    /// Call this from your library code when YOU decide to report to inspector,
    /// rather than having it happen automatically inside process().
    ///
    /// This method does NOT verify the event or return event data.
    /// If inspector is nil, this is a no-op.
    ///
    /// Note: avoFunctionEventId and avoFunctionEventHash are omitted because
    /// AvoEvent protocol has no eventId/eventHash fields.
    public func sendToInspector(event: AvoEvent) {
        guard let inspector = self.__INSPECTOR__ else { return }

        guard let avoEventOut = event.properties["analyticsDest"] else { return }

        let trackSchemaFromEventSelector = Selector(("avoFunctionTrackSchemaFromEvent:eventParams:"))
        if inspector.responds(to: trackSchemaFromEventSelector) == true {
            let _ = inspector.perform(trackSchemaFromEventSelector, with: avoEventOut.name, with: avoEventOut.properties)
        }
    }
}
